import 'dart:convert'; import 'package:injectable/injectable.dart'; import 'package:shared_preferences/shared_preferences.dart'; @injectable class SessionPersistenceService { final SharedPreferences _prefs; static const _key = 'last_session_v1'; SessionPersistenceService(this._prefs); Future<void> saveLastSession(Map<String, dynamic> data) => _prefs.setString(_key, jsonEncode(data)); Map<String, dynamic>? getLastSession() { final r = _prefs.getString(_key); return r != null ? Map<String, dynamic>.from(jsonDecode(r)) : null; } Future<void> clear() => _prefs.remove(_key); }